using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class QueryFunction
{
    private static readonly HashSet<string> AllowedColumns = new HashSet<string>
    {
        "id", "name", "email", "created_date", "status"
    };

    private static readonly HashSet<string> AllowedOperators = new HashSet<string>
    {
        "=", ">", "<", ">=", "<=", "LIKE", "IN"
    };

    [FunctionName("QueryFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            if (string.IsNullOrEmpty(connectionString))
            {
                return new BadRequestObjectResult("Database connection string not configured.");
            }

            var filters = new List<string>();
            var parameters = new List<SqlParameter>();
            var filterCount = 0;

            foreach (var param in req.Query)
            {
                var columnName = param.Key;
                var operatorValue = "LIKE";
                var value = param.Value.ToString();

                if (!AllowedColumns.Contains(columnName))
                {
                    continue;
                }

                if (value.Contains("||"))
                {
                    var parts = value.Split("||", StringSplitOptions.RemoveEmptyEntries);
                    if (parts.Length > 0)
                    {
                        operatorValue = parts[0];
                        value = parts.Length > 1 ? parts[1] : "";
                    }
                }

                if (!AllowedOperators.Contains(operatorValue))
                {
                    operatorValue = "=";
                }

                var parameterName = $"@param{filterCount}";
                filterCount++;

                switch (operatorValue)
                {
                    case "IN":
                        var values = value.Split(',');
                        var inParams = values.Select((v, i) => $"@inParam{filterCount}_{i}").ToArray();
                        parameters.AddRange(values.Select((v, i) => new SqlParameter($"@inParam{filterCount}_{i}", v)));
                        filters.Add($"[{columnName}] IN ({string.Join(",", inParams)})");
                        break;
                    case "LIKE":
                        parameters.Add(new SqlParameter(parameterName, $"%{value}%"));
                        filters.Add($"[{columnName}] LIKE {parameterName}");
                        break;
                    default:
                        parameters.Add(new SqlParameter(parameterName, value));
                        filters.Add($"[{columnName}] {operatorValue} {parameterName}");
                        break;
                }
            }

            var whereClause = filters.Any() ? "WHERE " + string.Join(" AND ", filters) : "";
            var sql = $"SELECT * FROM [dbo].[ReportTable] {whereClause}";

            using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            using var command = new SqlCommand(sql, connection);
            command.CommandTimeout = 30;

            foreach (var param in parameters)
            {
                command.Parameters.Add(param);
            }

            using var reader = await command.ExecuteReaderAsync();
            var results = new List<Dictionary<string, object>>();

            while (await reader.ReadAsync())
            {
                var row = new Dictionary<string, object>();
                for (int i = 0; i < reader.FieldCount; i++)
                {
                    row[reader.GetName(i)] = reader.GetValue(i) ?? DBNull.Value;
                }
                results.Add(row);
            }

            return new OkObjectResult(results);
        }
        catch (Exception ex)
        {
            return new StatusCodeResult(500);
        }
    }
}